const inboxId    = config['chatwoot_inbox_id']    || '';
const agentPhone = config['agent_phone']          || '';

const chatwootPublicUrl = (config['chatwoot_public_url'] || chatwootUrl).replace(/\/$/, '');

if (!accountId || !apiToken || !inboxId) {
  console.log('[chatwoot] Configuração incompleta — verifique chatwoot_account_id, chatwoot_api_token, chatwoot_inbox_id nas settings');
  return [{ json: { ok: false, skip: true, instancia, agentPhone, tel, customer_name } }];
}

// Step 1: Search for existing contact
let contactId;
try {
  const phoneSearch = tel.replace(/\D/g, '');
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: `${chatwootUrl}/api/v1/accounts/${accountId}/contacts/search?q=%2B${phoneSearch}&include_contacts=true`,
    headers: { 'api_access_token': apiToken }
  });
  const contacts = (res.payload || []);
  if (contacts.length > 0) {
    contactId = contacts[0].id;
    console.log('[chatwoot] Contato existente encontrado:', contactId);
  }
} catch(e) {
  console.log('[chatwoot] Erro ao buscar contato:', e.message);
}

// Step 2: Create contact if not found
if (!contactId) {
  try {
    const phoneE164 = '+' + tel.replace(/\D/g, '');
    const body = { name: customer_name || 'cliente', phone_number: phoneE164 };
    const created = await this.helpers.httpRequest({
      method: 'POST',
      url: `${chatwootUrl}/api/v1/accounts/${accountId}/contacts`,
      headers: { 'Content-Type': 'application/json', 'api_access_token': apiToken },
      body: JSON.stringify(body)
    });
    contactId = created.id;
    console.log('[chatwoot] Novo contato criado:', contactId);
  } catch(e) {
    console.log('[chatwoot] Erro ao criar contato:', e.message);
    return [{ json: { ok: false, error: e.message, instancia, agentPhone, tel, customer_name } }];
  }
}

// Step 3: Create conversation
let conversationId, conversationUrl;
try {
  const convRes = await this.helpers.httpRequest({
    method: 'POST',
    url: `${chatwootUrl}/api/v1/accounts/${accountId}/conversations`,
    headers: { 'Content-Type': 'application/json', 'api_access_token': apiToken },
    body: JSON.stringify({ contact_id: contactId, inbox_id: parseInt(inboxId, 10) })
  });
  conversationId = convRes.id;
  conversationUrl = `${chatwootPublicUrl}/app/accounts/${accountId}/conversations/${conversationId}`;
  console.log('[chatwoot] Conversa criada:', conversationId);
} catch(e) {
  console.log('[chatwoot] Erro ao criar conversa:', e.message);
  return [{ json: { ok: false, error: e.message, instancia, agentPhone, tel, customer_name } }];
}

return [{ json: { ok: true, instancia, agentPhone, conversationId, conversationUrl, customer_name, tel } }];

const { ok, skip, agentPhone, conversationUrl, customer_name, tel } = $json;
if (!agentPhone) return [{ json: { done: true } }];
const token = $env.WHATSAPP_ACCESS_TOKEN;
const phoneId = $env.WHATSAPP_PHONE_NUMBER_ID;
const version = $env.WHATSAPP_API_VERSION || 'v21.0';
const text = '🔔 *Nova solicitação de atendimento!*\n\n'
  + '👤 Cliente: ' + (customer_name || 'desconhecido') + '\n'
  + '📱 Telefone: +' + tel.replace(/\D/g, '') + '\n\n'
  + (conversationUrl ? '🔗 *Abrir conversa no Chatwoot:*\n' + conversationUrl
    : '⚠️ Atenda diretamente: wa.me/' + tel.replace(/\D/g, ''));
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/${version}/${phoneId}/messages`,
    headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
    body: JSON.stringify({ messaging_product: 'whatsapp', to: agentPhone, type: 'text', text: { body: text } })
  });
} catch(e) {}
return [{ json: { done: true } }];
